# app/controllers/admin/logs_controller.rb
class Admin::LogsController < ApplicationController
  before_action :require_admin

  def show
    filename = params[:log]

    # Validate filename format for security
    unless filename =~ /\A[a-zA-Z0-9_\-]+\.log\z/
      redirect_to admin_dashboard_path, alert: "Invalid log filename format."
      return
    end

    log_path = Rails.root.join('log', filename)

    # Critical security check: Ensure the resolved path is strictly within the logs directory.
    # This prevents path traversal attacks (e.g., params[:log] = '../../config/database.yml').
    unless File.expand_path(log_path).start_with?(File.expand_path(Rails.root.join('log')))
      redirect_to admin_dashboard_path, alert: "Access denied: Attempted to access file outside log directory."
      return
    end

    if File.exist?(log_path)
      @log_content = File.read(log_path)
    else
      redirect_to admin_dashboard_path, alert: "Log file '#{filename}' not found."
      return
    end
  rescue Errno::ENOENT
    redirect_to admin_dashboard_path, alert: "Log file '#{filename}' not found."
  rescue => e
    Rails.logger.error "Admin Log Viewer Error for '#{filename}': #{e.message}"
    redirect_to admin_dashboard_path, alert: "An error occurred while reading the log file."
  end

  private

  def require_admin
    # Replace this with your actual admin authorization logic.
    # Example assumes `current_user` method and `admin?` method on user object.
    unless current_user && current_user.admin?
      redirect_to root_path, alert: "You are not authorized to view log files."
    end
  end
end

